mapper.select:
/* IfWcsMoniterMapper.selectWcsIfHistory - WCS인터페이스 이력 COUNT 조회 */
SELECT COUNT(1)

 WHERE 1 = 1

/* IfWcsMoniterMapper.selectWcsIfHistory - WCS인터페이스 이력 조회 */
SELECT '0' AS CHK , A.*
WHERE 1 = 1

/* IfWcsMoniterMapper.selectWcsMoniterTable - 넥사크로 그리드 테이블 조회 */
SELECT unnest(string_to_array(CTCD_DTVALUE, ','))
  FROM TWORK_MST_CTCD_DT
 WHERE CTKEY 	  = #{@com.daiso.wms.interfaces.common.WcsPropertyUtil@CTKEY}
   AND CTCD_HDKEY = 'WCS_IF_LIST'
   AND CTCD_DTKEY = #{wcsIfCode}

/* IfWcsMoniterMapper.selectWcsMoniterStatistics - 인터페이스 모니터링 통계 */ SELECT MAX(CASE WHEN TB = 'SCTGWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SCTGWCS_SUCCESS" , MAX(CASE WHEN TB = 'SCTGWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SCTGWCS_FAIL" , MAX(CASE WHEN TB = 'SICWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SICWCS_SUCCESS" , MAX(CASE WHEN TB = 'SICWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SICWCS_FAIL" , MAX(CASE WHEN TB = 'SIBWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SIBWCS_SUCCESS" , MAX(CASE WHEN TB = 'SIBWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SIBWCS_FAIL" , MAX(CASE WHEN TB = 'SRMWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SRMWCS_SUCCESS" , MAX(CASE WHEN TB = 'SRMWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SRMWCS_FAIL" , MAX(CASE WHEN TB = 'SOBWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SOBWCS_SUCCESS" , MAX(CASE WHEN TB = 'SOBWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SOBWCS_FAIL" , MAX(CASE WHEN TB = 'UNITWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "UNITWCS_SUCCESS" , MAX(CASE WHEN TB = 'UNITWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "UNITWCS_FAIL" , MAX(CASE WHEN TB = 'SIVMMWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SIVMMWCS_SUCCESS" , MAX(CASE WHEN TB = 'SIVMMWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SIVMMWCS_FAIL" , MAX(CASE WHEN TB = 'SIVHDWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SIVHDWCS_SUCCESS" , MAX(CASE WHEN TB = 'SIVHDWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SIVHDWCS_FAIL" , MAX(CASE WHEN TB = 'RIVRVWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "RIVRVWCS_SUCCESS" , MAX(CASE WHEN TB = 'RIVRVWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "RIVRVWCS_FAIL" , MAX(CASE WHEN TB = 'SIVWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "SIVWCS_SUCCESS" , MAX(CASE WHEN TB = 'SIVWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "SIVWCS_FAIL" , MAX(CASE WHEN TB = 'RIVMSCWCS' AND SUCCEEDED = 1 THEN CNT ELSE 0 END) AS "RIVMSCWCS_SUCCESS" , MAX(CASE WHEN TB = 'RIVMSCWCS' AND SUCCEEDED = 0 THEN CNT ELSE 0 END) AS "RIVMSCWCS_FAIL" FROM ( SELECT A.TB, A.SUCCEEDED, COUNT(*) AS CNT FROM ( SELECT 'SCTGWCS' AS TB , CASE WHEN SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , INSERTDATE FROM TWORK_INTF_SCTGWCS
WHERE INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SICWCS' AS TB , CASE WHEN SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , INSERTDATE FROM TWORK_INTF_SICWCS_HD
WHERE INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SIBWCS' AS TB , CASE WHEN TISIB.SUCCEEDED = 'true' OR TIRIB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISIB.INSERTDATE FROM TWORK_INTF_SIBWCS TISIB LEFT OUTER JOIN TWORK_INTF_RIBWCS TIRIB ON TISIB.IB_NUMBER = TIRIB.IB_NUMBER
WHERE TISIB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SRMWCS' AS TB , CASE WHEN TISIB.SUCCEEDED = 'true' OR TIRIB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISIB.INSERTDATE FROM TWORK_INTF_SRMWCS TISIB LEFT OUTER JOIN TWORK_INTF_RRMWCS TIRIB ON TISIB.RM_NUMBER = TIRIB.RM_NUMBER WHERE TISIB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO} UNION ALL SELECT 'SOBWCS' AS TB , CASE WHEN TISOB.SUCCEEDED = 'true' OR TIROB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISOB.INSERTDATE FROM TWORK_INTF_SOBWCS TISOB LEFT OUTER JOIN TWORK_INTF_ROBWCS TIROB ON TISOB.OB_NUMBER = TIROB.OB_NUMBER WHERE TISOB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO} UNION ALL SELECT 'UNITWCS' AS TB , CASE WHEN TISOB.SUCCEEDED = 'true' OR TIROB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISOB.INSERTDATE FROM TWORK_INTF_SOBWCS TISOB LEFT OUTER JOIN TWORK_INTF_ROBWCS TIROB ON TISOB.OB_NUMBER = TIROB.OB_NUMBER
WHERE TISOB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SIVMMWCS' AS TB , CASE WHEN TISOB.SUCCEEDED = 'true' OR TIROB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISOB.INSERTDATE FROM TWORK_INTF_SIVMMWCS TISOB LEFT OUTER JOIN TWORK_INTF_RIVMMWCS TIROB ON TISOB.IVMM_NUMBER = TIROB.IVMM_NUMBER
WHERE TISOB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SIVHDWCS' AS TB , CASE WHEN TISOB.SUCCEEDED = 'true' OR TIROB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISOB.INSERTDATE FROM TWORK_INTF_SIVHDWCS TISOB LEFT OUTER JOIN TWORK_INTF_RIVHDWCS TIROB ON TISOB.IVHD_NUMBER = TIROB.IVHD_NUMBER
WHERE TISOB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'RIVRVWCS' AS TB , CASE WHEN SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , INSERTDATE FROM TWORK_INTF_RIVRVWCS
WHERE INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'SIVWCS' AS TB , CASE WHEN TISOB.SUCCEEDED = 'true' OR TIROB.SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , TISOB.INSERTDATE FROM TWORK_INTF_SIVWCS TISOB LEFT OUTER JOIN TWORK_INTF_RIVWCS TIROB ON TISOB.IV_NUMBER = TIROB.IV_NUMBER
WHERE TISOB.INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
UNION ALL SELECT 'RIVMSCWCS' AS TB , CASE WHEN SUCCEEDED = 'true' THEN 1 ELSE 0 END AS SUCCEEDED , INSERTDATE FROM TWORK_INTF_RIVMSCWCS
WHERE INSERTDATE BETWEEN #{INSERTDATE_FROM} AND #{INSERTDATE_TO}
) A GROUP BY A.TB, A.SUCCEEDED )

/* IfWcsMoniterMapper.selectWcsMoniterField - 넥사크로 그리드 헤더 조회 */
SELECT STRING_AGG(FIELD, ';' ORDER BY COLUMN_ID) AS FIELD
FROM (SELECT SUBSTR(A.TABLE_NAME, INSTR(A.TABLE_NAME, '_', 1, 2)+1, LENGTH(A.TABLE_NAME)) || '_' || A.COLUMN_NAME AS FIELD
		, A.COLUMN_ID
	FROM ALL_TAB_COLUMNS A
	WHERE A.TABLE_NAME = #{tableNm}
	ORDER BY A.TABLE_NAME, A.COLUMN_ID
	)

mapper.delete:
		DELETE FROM #{tableName} A
		 WHERE EXISTS (
               SELECT 1
                 FROM #{joinTable} X
                WHERE A.#{joinKey} = X.#{joinKey}
                  AND X.#{keyName} = #{keyValue}
               )

mapper.select:
SELECT DISTINCT R_OBUNIT_SEQ
  FROM TWORK_INTF_ROBUNITPKWCS
 WHERE ORDER_NUMBER = #{OB_NUMBER}

mapper.insert:
/* IfWcsInvnMapper.insertWcsInvnRevisionRes - WCS재고조정내역 추가 */

	SELECT nextval('seq_twork_intf_rivrvwcs')

INSERT INTO TWORK_INTF_RIVRVWCS
(
	  R_IVRV_SEQ
	, WCS_INTERFACE_ID
	, WMS_INTERFACE_ID
	, CTKEY
	, OWKEY
	, IVRV_NUMBER
	, PRODUCT_CODE
	, QUANTITY_VALUE
	, QUANTITY_UNIT
	, EFFECTIVE_DATE
	, LOCATION_CODE
	, REASON
	, CARGO_LOCATION
	, HOLD_STATUS
	, LICENSE_PLATE_NUMBER
	, SUCCEEDED
	, ERROR_VALUE
	, ERROR_REASON
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
) VALUES(
	  #{R_IVRV_SEQ}
	, #{WCS_INTERFACE_ID}
	, #{WMS_INTERFACE_ID}
	, #{CTKEY}
	, #{OWKEY}
	, #{IVRV_NUMBER}
	, #{PRODUCT_CODE}
	, #{QUANTITY_VALUE}
	, #{QUANTITY_UNIT}
	, #{EFFECTIVE_DATE}
	, #{LOCATION_CODE}
	, #{REASON}
	, #{CARGO_LOCATION}
	, #{HOLD_STATUS}
	, #{LICENSE_PLATE_NUMBER}
	, #{SUCCEEDED}
	, #{ERROR_VALUE}
	, SUBSTR(#{ERROR_REASON}, 1, 255)
	, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')
	, 'WMS_ADJ'
	, TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')
	, 'WMS_ADJ'
)

mapper.select:
/* IfWcsInvnMapper.selectItemExpiredate - WCS재고조정 상품유통기한조회 추가 */
SELECT A.ICKEY
     , A.UOM
     , A.IVATKEY
	 , TO_CHAR(TO_DATE(SUBSTR(A.EXPIREDATE, 1, 8), 'YYYYMMDD'), 'YYYY-MM-DD') AS EXPIREDATE
FROM TWORK_INFO_IVAT A
WHERE A.CTKEY = #{ctkey}
  AND A.OWKEY = #{owkey}
